const Q_ECONOMICS_2001=[{"id": "objective>Economics>2001>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A vertical supply curve indicates that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the same fixed quantity will be supplied no matter the price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the quantity supplied is responsive to price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in price will result in an increase in the quantity supplied </div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is a fixed price for the commodity below which no supply will be made.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It indicates fixed in the quantity supplied of a commodity irrespective of the change in its price. This is the case of a perfectly inelastic supply curve which means the responsiveness of quantity supplied to change in price is zero.</div>", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2001>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A change in supply is best described as a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">movement along the supply curve </div>", "<div style=\"font-family:Cambria;font-size:17px;\">shift of the supply curve to the right </div>", "<div style=\"font-family:Cambria;font-size:17px;\">shift of the supply curve to the left </div>", "<div style=\"font-family:Cambria;font-size:17px;\">shift of the supply curve to the left or to the right.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Change in supply is the increase or decrease in supply of goods and services due to changes in the other factors affecting supply other than the price (e.g. cost of production, weather, etc.).</div>", "topic": "THEORY OF SUPPLY : DISTINCTION BETWEEN CHANGE IN QUANTITY SUPPLIED AND CHANGE IN SUPPLY"}, {"id": "objective>Economics>2001>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a generalization is made based on observed facts, it is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> normative reasoning </div>", "<div style=\"font-family:Cambria;font-size:17px;\">theoretical reasoning </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> inductive reasoning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deductive reasoning</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Inductive reasoning involves drawing a conclusion from particular to general. By saying economists distil principles from facts, we are describing the inductive or empirical method.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : SCIENTIFIC APPROACH"}, {"id": "objective>Economics>2001>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  <br/> The diagram above shows the total utility curve. At the point M, marginal utility </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is zero </div>", "<div style=\"font-family:Cambria;font-size:17px;\">diminishes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is unity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When total utility is at its highest marginal utility is at zero and when total utility beings to fall, marginal utility attains negative value. This explains the law of diminishing marginal utility. </div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : MARGINAL RATE OF SUBSTITUTION (MRS)"}, {"id": "objective>Economics>2001>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a demand curve, the relationship between price and quantity is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">indeterminate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">inverse  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nil</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Because the demand curve slope downward from left to right, meaning that less quantity will be demanded at higher price, ceteris paribus.the relationship between price and quantity demanded is negative or inverse</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2001>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At consumer equilibrium, the slope of the indifference curve is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">half the slope of the budget constraint line </div>", "<div style=\"font-family:Cambria;font-size:17px;\">greater than the slope of the budget constraint line </div>", "<div style=\"font-family:Cambria;font-size:17px;\">less than the slope of the budget constraint line </div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal to the slope of the budget constraint line </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Indifference curve is the locus of points-particular combination or bundle of goods- which yield the same utility. While budget line showing the maximum amount of goods in different combinations, which a consumer can obtain from his or her income. Given the indifference map (all the indifference curves which rank the preferences of the consumer) of the consumer and its budget line, the equilibrium is defined as the point of tangency of the budget line with the highest possible indifference curve.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM"}, {"id": "objective>Economics>2001>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the arithmetic mean of 1, 2, 5, 6, x, 16 and 18 is 8.0, find value of x.  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8.5 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.0 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.0</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mean = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">∑x</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">n</span> <br/>  <br/> 8 = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1+2+5+6+x+16+18 </span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">7</span> <br/>  <br/> 8 = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">48+x</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">7</span> <br/>   Cross multiply <br/>  48 + x = 7 x 8  <br/>  x = 56 - 48  <br/> = 8.0</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2001>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the price elasticity of demand for a good is 0.43, an increase in the price of the good will result in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> an increase in profit by 43% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in profit by 43% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a net gain  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a net loss</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The price elasticity of demand measures the responsiveness of the quantity demanded to a change in price. If the price elasticity of demand for a good is less than 1 (0.43 in this case), it means the demand is inelastic. Inelastic demand means that the percentage change in quantity demanded is less than the percentage change in price.  <br/>  <br/> Therefore, an increase in price will result in net gain in revenue and possibly profit because the fall in quantity sold is proportionally smaller.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2001>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A consumer's scale of preference is an arrangement of his </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">scarce resources in order of importance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">requirements and how to satisfy them </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sources of income and their importance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">needs in order of importance.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Scale of preference is the ordering of consumer's want in order of their priority. It is also a list that shows the need of a consumer in order of magnitude.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT"}, {"id": "objective>Economics>2001>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For a supply curve, an increase in the price of a commodity will result in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the quantity supplied</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the quantity supplied</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in supply</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There exist a positive relationship between price and quantity supplied of a good which implies a change in quantity supplied resulting from change in price other than other factors affecting supply.</div>", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2001>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The fixing of the price of an item above or below the equilibrium price is most likely to take place in a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">free market economy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">developed economy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mixed economy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">centrally planned economy</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Price fixing is a practice where the price of an item is set by a central authority, rather than by the forces of supply and demand. This is most likely to occur in a centrally planned economy, where the government controls all major aspects of economic production and distribution. In a free market economy, prices are determined by supply and demand. In a mixed economy, both market forces and government intervention determine prices. In a developed economy, the level of economic development does not necessarily determine the method of price setting.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER IMPERFECT MARKET"}, {"id": "objective>Economics>2001>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A normal good with close substitutes is likely to have its price elasticity of demand </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">less than unity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">between zero and one </div>", "<div style=\"font-family:Cambria;font-size:17px;\">greater than unity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal to unity.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The price elasticity of demand measures how much the quantity demanded of a good responds to a change in the price of that good. If a good has close substitutes, consumers can easily switch to another product when the price of the good increases, hence, the demand is elastic and the price elasticity of demand is greater than unity.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2001>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major problem facing all economies is how to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">improve trade among nations </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase consumption of imported goods </div>", "<div style=\"font-family:Cambria;font-size:17px;\">allocate scarce resources </div>", "<div style=\"font-family:Cambria;font-size:17px;\">transform from a developing to a developed economy.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A major problem facing economies is resources allocation in that economic units tend to want more than the economy can provide. Scarcity simply means limited in supply. If goods were in abundant supply, there wouldn't have been the problem of scarcity; the problem of scarcity necessitates a choice among alternative uses of scarce resources.scare resources result to the study of economics.</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>2001>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a free market economy, the price system allocates resources </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">to ensure general welfare </div>", "<div style=\"font-family:Cambria;font-size:17px;\">under government's directives </div>", "<div style=\"font-family:Cambria;font-size:17px;\">to reduce poverty </div>", "<div style=\"font-family:Cambria;font-size:17px;\">to their best alternative uses</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a free enterprise market, the interaction of demand and supply forces are just automatically operated to allocate resources into an alternative uses.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>2001>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Economics is regarded as a social science because it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">adopts the scientific method in the study of human behaviour </div>", "<div style=\"font-family:Cambria;font-size:17px;\">adopts the scientific method in production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is an agent of socialization </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> deals with social problems.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The adoption of scientific method in the study of human behavior in economics allowed it to be regarded as social science.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>2001>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The long run is a period during which a firm </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">replaces all its inputs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sells inputs to purchase fixed assets </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sources all its inputs from within </div>", "<div style=\"font-family:Cambria;font-size:17px;\">varies all its input</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the long run, there exist the needs for a very large scale output that will require variation in all inputs. In the long run, all the costs vary, hence no fixed factor.</div>", "topic": "THEORY OF PRODUCTION (2) : CONCEPTS OF PRODUCTION"}, {"id": "objective>Economics>2001>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A production function relates</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wage to profit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">output to input</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost to input </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost to output.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A production function in economics relates the output of a production process to the inputs or factors of production. It represents how much output (goods or services) a firm can produce with a given amount of inputs. Therefore, the option 'output to input' is correct.</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCTION FUNCTIONS & LAWS OF RETURNS"}, {"id": "objective>Economics>2001>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An important feature of perfect competition is that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the movement of goods and services is restricted </div>", "<div style=\"font-family:Cambria;font-size:17px;\">prices are centrally administered </div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is adequate knowledge of existing prices </div>", "<div style=\"font-family:Cambria;font-size:17px;\">individual economic units an influence prices.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">With perfect knowledge of market condition (price), no single buyer or seller can be discriminated against since neither of the parties (buyer and seller) is price giver.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2001>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An imperfect market exists where </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the product is homogenous </div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is a perfect information among the new few buyers and sellers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the location of some sellers gives them an advantage over others </div>", "<div style=\"font-family:Cambria;font-size:17px;\">both buyers and sellers have free entry into and free exit from the market.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a firm enjoys location advantage and uses it to influence the price, it is no longer operating under perfect market because of its ability to influence the price.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2001>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A firm's shut-down point is reached when the average revenue fails to cover the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marginal cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">average fixed cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">average total cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average variable cost</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Average variable cost, when combined with price, indicates whether or not a firm should shut down production in the short run. If price is greater than average variable cost, then the firm is able to pay all variable cost and a portion of fixed cost. Even though it might be incurring an economic loss, it will lose less by producing than by shutting down production. If, however, price is less than average variable cost, then the firm is better off shutting down production.</div>", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE"}, {"id": "objective>Economics>2001>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The table below shows a demand schedule for eggs:  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Price per Dozen  <br/>  (₦)</td><td style=\"border:1px solid black;text-align:center;\"> Qty. Demanded  <br/>  (in dozen)</td><td style=\"border:1px solid black;text-align:center;\"> Qty. Supplied  <br/>  (in dozen) <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">100</td><td style=\"border:1px solid black;text-align:center;\"> 410 </td><td style=\"border:1px solid black;text-align:center;\">570 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">90</td><td style=\"border:1px solid black;text-align:center;\"> 450</td><td style=\"border:1px solid black;text-align:center;\"> 530 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">80</td><td style=\"border:1px solid black;text-align:center;\"> 490</td><td style=\"border:1px solid black;text-align:center;\">490 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">70</td><td style=\"border:1px solid black;text-align:center;\"> 530</td><td style=\"border:1px solid black;text-align:center;\">450 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">60</td><td style=\"border:1px solid black;text-align:center;\"> 570</td><td style=\"border:1px solid black;text-align:center;\">410</td></tr></table></div> <br/> What is the equilibrium price?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦100 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦80 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦60</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦110 </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equilibrium price is the price at which quantity demanded equals quantity supplied. Hence, equilibrium price is ₦80.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>2001>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major advantage of specialization and division of labour is that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">trade unions will be encouraged </div>", "<div style=\"font-family:Cambria;font-size:17px;\">workers will be adequately rewarded </div>", "<div style=\"font-family:Cambria;font-size:17px;\">time wastage will be minimized </div>", "<div style=\"font-family:Cambria;font-size:17px;\">there will be a ready market for labour.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">With division of labour, a worker doesn't need to move from one piece of work to another and having been specialized on a given task, he now concentrate actively without wasting time.</div>", "topic": "THEORY OF PRODUCTION (1) : DIVISION OF LABOUR & SPECIALISATION"}, {"id": "objective>Economics>2001>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the long run, a monopolist maximizes his profit when the marginal cost equals</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marginal revenue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">total revenue  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">average cost.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In economics, a monopolist maximizes his profit when the marginal cost (MC) equals the marginal revenue (MR). This is because the marginal cost is the cost of producing one more unit of a good, and the marginal revenue is the revenue gained from selling one more unit of a good. When MC=MR, the monopolist is maximizing his profit because he is producing the exact amount of goods that will generate the highest possible profit.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2001>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an example of a fixed cost? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> fuel cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rent on building </div>", "<div style=\"font-family:Cambria;font-size:17px;\">electricity bill</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transportation cost</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fixed cost is a cost that does not change on increase or decrease in the amount of goods or services produced. Rent on building does not have to change if the output of the firm must increase or decrease. Other examples are: Land and building, Motor car etc.</div>", "topic": "THE CONCEPT OF COST & REVENUE : EXPLICIT AND IMPLICIT COSTS"}, {"id": "objective>Economics>2001>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If government fixes price below the equilibrium price, what effect will it have on demand? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">quantity demanded and supplied will be equal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">quantity supplied will be greater than quantity demanded </div>", "<div style=\"font-family:Cambria;font-size:17px;\">quantity demanded will decrease </div>", "<div style=\"font-family:Cambria;font-size:17px;\">quantity demanded will increase.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fixing price below equilibrium is called price ceiling. The price has been fixed below market determined price and at lower price more quantity of goods are demanded by consumers.there is surplus when price is fixed below the equilibrum.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>2001>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Internal economies of scale are expected to bring about </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a decrease in long-run average cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in short-run average cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in short-run average cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in long-run average cost.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Internal economies of scale refer to the cost-saving advantages that a business obtains due to expansion. They are called 'internal' because they are internal to the company, i.e., they arise from the growth of the firm itself. As a firm increases its scale of operations, it can achieve lower costs per unit of output. This is reflected in a decrease in long-run average cost.</div>", "topic": "THEORY OF PRODUCTION (1) : SCALE OF PRODUCTION"}, {"id": "objective>Economics>2001>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An industry is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">firm producing differentiated commodities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">group of firms producing distinct commodities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">group of firms producing related commodities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">company producing unrelated commodities.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An industry is defined as group of firms producing similar or identical products. It can also be defined as a group of manufacturers or businesses that produce a particular kind of goods or services. </div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2001>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To facilitate the exportation of crude oil from Nigeria, special </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">railway lines were constructed to connect the major oil wells to the ports </div>", "<div style=\"font-family:Cambria;font-size:17px;\">roads were built to connect the major oil wells to the ports </div>", "<div style=\"font-family:Cambria;font-size:17px;\">airstrips were constructed for jets to evacuate the oil </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pipelines were laid to connect the major oil wells to the ports</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Discovering, extracting, shipping, and refining crude is a long process, and the infrastructure needed to support the process must be in place. This involves thousands of miles of oil pipelines across countries, storage facilities in major oil trading hubs, and multiple refineries.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : ONSHORE & OFFSHORE OF THE OIL SECTOR"}, {"id": "objective>Economics>2001>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The raising of funds by selling stocks to the public is called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stock financing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">equity financing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">loan financing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debt financing</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equity financing is one of the main sources of raising fund by joint stock companies from members of the public through issuing of shares and giving the shareholders certificate of participation in ownership of the corporation.</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>2001>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A disadvantage of concentrating industries in an area is that it could </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bring about diseconomies of scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lead to collusion among the firms </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the cost of production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">result in environmental pollution</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Environmental pollution can occur when a large number of firm concentrated in particular area emit different waste substances into the environment which are capable of polluting the environment.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION"}, {"id": "objective>Economics>2001>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The losses suffered by a sole proprietor are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">not limited to the amount invested </div>", "<div style=\"font-family:Cambria;font-size:17px;\">limited to the amount invested </div>", "<div style=\"font-family:Cambria;font-size:17px;\">usually less than that amount invested </div>", "<div style=\"font-family:Cambria;font-size:17px;\">usually equal to the amount invested.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Unlimited liability is one of the main disadvantages of sole proprietorship because, in the event of failure in the business, the assets of the business, his private assets and other properties may be claimed by his creditor.</div>", "topic": "BUSINESS ORGANISATION : SOLE PROPRIETOSHIP"}, {"id": "objective>Economics>2001>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the agricultural sector, improved extension services facilitate </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">livestock production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">arable crop production  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mobility of labour </div>", "<div style=\"font-family:Cambria;font-size:17px;\">acquisition of techniques.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Extension service is one of the approaches used to promote acquisition of new techniques of farming among farmers.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>2001>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The capital market is a market for trading or financing assets such as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">treasury bills  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">commercial papers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bankers' acceptances</div>", "<div style=\"font-family:Cambria;font-size:17px;\">long-term securities.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Long-term securities other than shares consist of securities other than shares that have an original maturity of more than one year. It is an instrument in the capital market.</div>", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC"}, {"id": "objective>Economics>2001>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The distribution channel that contributes most to the cost of production is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">producer-retailer-consumer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">producer-wholesaler-consumer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">producer-wholesaler-retailer-consumer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">producer – retailer – wholesaler - consumer.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The normal channel of distribution is from producer to wholesaler and to the retailer and to the final consumer.</div>", "topic": "DISTRIBUTIVE TRADE : THE WHOLESALER"}, {"id": "objective>Economics>2001>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in the discount rate is an indication of a central bank's intention to pursue </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a contractionary monetary policy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a disciplined monetary policy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a dynamic monetary policy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an expansionary monetary policy.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Discount rate is the rate at which commercial banks borrow from central banks. When this rate increases, commercial banks are discouraged from borrowing and their ability to lend to the public will be reduced. Thereby, implying tight monetary policy. <br/>  <br/> Contractionary monetary policy is when a central bank uses its monetary policy tools to fight inflation by increasing interest rate and discount rate.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>2001>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">GNP is not a good measure of social welfare because there are unrecorded </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">social costs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">indirect taxes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">transfer payments </div>", "<div style=\"font-family:Cambria;font-size:17px;\">government subsidies.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">While GNP measures production, it is also commonly used to measure the welfare of a country. Real GNP growth is seen as an improvement in living standards. Unfortunately, GNP is not a perfect measure of social welfare and even has its limitation in measuring economic output.</div>", "topic": "NATIONAL INCOME : PROBLEMS OF NATIONAL INCOME"}, {"id": "objective>Economics>2001>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">National debt is an expected outcome of a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">surplus budget </div>", "<div style=\"font-family:Cambria;font-size:17px;\">balanced budget </div>", "<div style=\"font-family:Cambria;font-size:17px;\">consolidated budget</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deficit budget</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">National debt can be internal or external when debt is incurred that means expenditure is more than income which is known as deficit budget.there will be need for government to borrow.</div>", "topic": "PUBLIC FINANCE : BUDGET"}, {"id": "objective>Economics>2001>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Money may not be accepted as a store of value if </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it is easily transferable </div>", "<div style=\"font-family:Cambria;font-size:17px;\">its value is unstable </div>", "<div style=\"font-family:Cambria;font-size:17px;\">its value is stable </div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is easily divisible</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Money is the most liquid asset of all assets. But it may lose much of its value in time of inflation. Therefore, money is not a perfect store of value because its purchasing power can change.</div>", "topic": "MONEY : VALUE OF MONEY"}, {"id": "objective>Economics>2001>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, revenue sharing from the Federation Account is between the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">federal and state governments and the senate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">federal, state and local governments </div>", "<div style=\"font-family:Cambria;font-size:17px;\">federal and state governments and the parastatals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">executive, the judiciary and the legislature.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria operates federal system of government which has three(3) tiers and revenue sharing is based on these tiers which are; federal, state and local government.</div>", "topic": "PUBLIC FINANCE : INTRODUCTION"}, {"id": "objective>Economics>2001>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the labour force in a given community is 2,000,000, in the wage employment 200,000 and the unemployed are 80,000, what is the unemployment rate in the community? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.0% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.0%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40.0%.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Unemployment</td><td style=\"text-align:center;\">rate</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">No of Unemployed<hr size=\"1\" />Labour force</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">80,000<hr size=\"1\" />2,000,000</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td></tr></table></div>  <br/>   = 4%</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT"}, {"id": "objective>Economics>2001>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A tax that increases at a higher percentage as income increases is called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a progressive tax </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a regressive tax </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a proportional tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an income tax</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A progressive tax is a tax system that takes a larger percentage of income from people earning larger income (e.g) P.A.Y.E-Pay As You Earn.</div>", "topic": "PUBLIC FINANCE : PRINCIPLE OF TAXATION"}, {"id": "objective>Economics>2001>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In order to accelerate economic development, a country must </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pursue a high population growth rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stimulate her population growth rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pursue an incremental population policy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pursue a rational population policy</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Population is considered as an important determinant of economic growth. In this respect population is working both as a stimulant as well as hurdles to economic growth. Firstly, population provides labour and entrepreneurship as an important factor service. However, growth of population at a higher rate usually eat up all the benefits of economic development leading to a slow growth of per capita income. Therefore, the government pursue a rational policy.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>2001>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Economic growth can be accelerated through </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increased current consumption </div>", "<div style=\"font-family:Cambria;font-size:17px;\">balancing of savings and consumption </div>", "<div style=\"font-family:Cambria;font-size:17px;\">postponement of current consumption</div>", "<div style=\"font-family:Cambria;font-size:17px;\">planned current consumption.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Economic growth can be accelerated through the postponement of current consumption. This is because when current consumption is postponed, it leads to savings. These savings can then be invested in productive ventures which can lead to an increase in output and hence economic growth. This concept is based on the theory of consumption and savings which states that when income is not used for consumption, it is saved and these savings form the basis for investment.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2001>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The efficiency of labour can be increased by  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">engaging expatriates only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">retirement of workers on a regular basis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">placing an embargo on recruitment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a constant training of workers</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> Efficiency of labour can be increased if the worker has prospects of promotion, honour and reward. The desire to work better and improve oneself must be stimulated by providing sufficient incentives to work. It is also possible to raise productivity by motivating the workers prop­erly.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR"}, {"id": "objective>Economics>2001>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The price paid for labour services is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wage rate  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">income rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">commission rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">salary rate</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wage is the price paid to the labourer for the services rendered. A wage may be defined as the sum of money paid under contract by an employer to worker for services rendered. </div>", "topic": "FACTORS OF PRODUCTION & THEIR THEORIES : WAGES"}, {"id": "objective>Economics>2001>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In national income accounting, NNP is derived by subtracting from the GNP </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> transfer payments </div>", "<div style=\"font-family:Cambria;font-size:17px;\">allowance for wastage </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> capital consumption</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indirect taxes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Net National Product is defined as Gross National Product less Depreciation( Also called capital consumption allowance).</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>2001>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The reduction of high fertility rate is a measure in population control designed to make the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">male population higher than the female</div>", "<div style=\"font-family:Cambria;font-size:17px;\">female and male population equal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">growth in population more sustainable </div>", "<div style=\"font-family:Cambria;font-size:17px;\">female population higher than the male.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reduction in the fertility as a population control policy is necessary to maintain social stability.</div>", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION"}, {"id": "objective>Economics>2001>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A country with over-valued currency will </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> decrease her foreign reserve </div>", "<div style=\"font-family:Cambria;font-size:17px;\">have increased demand for her exports </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase her foreign reserve </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> expect balance of payments surplus.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a currency is overvalued its exports will decline as they will become more expensive for other countries. On the other hand,their imports will increase because they will become cheaper. Therefore, a country with an overvalued currency will have a trade disadvantage i.e., overvalued currency negatively affects the trade balance</div>", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE"}, {"id": "objective>Economics>2001>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The loans from the World Bank to developing countries are mainly to support </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> the establishment of more universities </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> capital-intensive technology </div>", "<div style=\"font-family:Cambria;font-size:17px;\">their low level of consumption</div>", "<div style=\"font-family:Cambria;font-size:17px;\">infrastructural investments</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Loans for infrastructural investments are investments that cover the basic area of an economy.it is loan for capital project.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC"}, {"id": "objective>Economics>2001>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major reason why nations engage in international trade is that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nations are substantially different in their endowments of economic resources </div>", "<div style=\"font-family:Cambria;font-size:17px;\">it affords the trading nations the opportunity to earn high profit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">it allows free movement of factors of production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">it makes possible the use of capital-intensive method of production. </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">No nation is self reliant or self-sufficient, nations must trade with each other since there is variability in natural resources endowment.Difference in natural resources is the major reason for foreign trade.</div>", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE"}];
